I made a management command to populate the initial data. It basically performs a query for each translatable model doing something like:

     UPDATE table SET a_column_XX = a_column

where XX is the default language. I'm using Django 1.9

    from django.core.management.base import BaseCommand
    from django.db import transaction
    from django.conf import settings
    from django.db.models import Func

    class RawColumn(Func):
        template = '%(expressions)s'

    class Command(BaseCommand):

        @transaction.atomic
        def handle(self, *args, **options):
            from modeltranslation.translator import translator

            for model, options in translator._registry.items():
                if not options.fields:
                    continue

                columns_to_populate = dict()
                for translatable_field in options.fields:

                    column_to_populate = '%s_%s' % (translatable_field, settings.LANGUAGE_CODE)

                    model_field = [field for field in model._meta.fields if field.name == translatable_field]
                    if not model_field:
                        raise Exception("Model field not found")

                    attname, raw_column_name= model_field[0].get_attname_column()

                    columns_to_populate[column_to_populate] = RawColumn(raw_column_name)

                if columns_to_populate:
                    model.objects.update(**columns_to_populate)

